   147→    async function loadData() {
   148→      try {
   149→        const [offersRes, candidatesRes, jobsRes] = await Promise.all([
   150→          fetch('/api/onboarding/offers'),
   151→          fetch('/api/recruiter/candidates'),
   152→          fetch('/api/jobs')
   153→        ]);
   154→
   155→        offersData = await offersRes.json();
   156→        candidatesData = await candidatesRes.json();
   157→        jobsData = await jobsRes.json();
   158→
   159→        renderOffers();
   160→        updateStats();
   161→        populateDropdowns();
