   165→    }
   166→
   167→    function renderOffers() {
   168→      const tbody = document.getElementById('offers-tbody');
   169→
   170→      if (offersData.length === 0) {
   171→        tbody.innerHTML = `
   172→          <tr>
   173→            <td colspan="6" class="px-6 py-12 text-center text-gray-400">
   174→              <i class="fas fa-inbox text-4xl mb-4 block"></i>
   175→              <p>No offers created yet</p>
   176→            </td>
   177→          </tr>
   178→        `;
