   291→
   292→    async function sendOffer(offerId) {
   293→      if (!confirm('Send this offer to the candidate?')) return;
   294→
   295→      try {
   296→        const res = await fetch(`/api/onboarding/offers/${offerId}/send`, {
   297→          method: 'POST'
   298→        });
   299→
   300→        if (!res.ok) throw new Error('Failed to send offer');
   301→
   302→        alert('Offer sent successfully!');
   303→        loadData();
   304→      } catch (err) {
   305→        console.error('Error sending offer:', err);
   306→        alert('Failed to send offer. Please try again.');
   307→      }
   308→    }
   309→
   310→    loadData();
