   141→    async function loadJobs() {
   142→      try {
   143→        const url = currentFilter === 'all' ? '/recruiter/jobs' : `/recruiter/jobs?status=${currentFilter}`;
   144→        const data = await apiCall(url);
   145→        if (!data) return;
