   159→
   160→    document.addEventListener('DOMContentLoaded', async () => {
   161→      const user = await checkAuth();
   162→      if (!user) {
   163→        window.location.href = '/login.html';
   164→        return;
   165→      }
   166→      if (!user.company_id && user.role !== 'recruiter') {
   167→        window.location.href = '/dashboard.html';
   168→        return;
   169→      }
   170→
   171→      const name = user.name || user.email.split('@')[0];
   172→      document.getElementById('user-name').textContent = name;
   173→      document.getElementById('user-avatar').textContent = name.charAt(0).toUpperCase();
   174→      document.getElementById('company-name').textContent = user.company_name || 'Company';
   175→      document.getElementById('dropdown-user-name').textContent = name;
   176→      document.getElementById('dropdown-user-email').textContent = user.email;
   177→
   178→      // Setup user menu dropdown
   179→      const userMenuToggle = document.getElementById('user-menu-toggle');
   180→      const userDropdownMenu = document.getElementById('user-dropdown-menu');
   181→      if (userMenuToggle && userDropdownMenu) {
   182→        userMenuToggle.addEventListener('click', (e) => {
   183→          e.stopPropagation();
   184→          userDropdownMenu.classList.toggle('active');
   185→        });
   186→        document.addEventListener('click', () => {
   187→          userDropdownMenu.classList.remove('active');
   188→        });
   189→      }
   190→
   191→      // Setup filter tabs
   192→      document.querySelectorAll('.filter-tab').forEach(tab => {
   193→        tab.addEventListener('click', () => {
   194→          document.querySelectorAll('.filter-tab').forEach(t => t.classList.remove('active'));
   195→          tab.classList.add('active');
   196→          currentFilter = tab.dataset.status;
   197→          renderApplications();
   198→        });
   199→      });
   200→
   201→      // Setup job filter
   202→      document.getElementById('job-filter').addEventListener('change', (e) => {
   203→        currentJob = e.target.value;
   204→        renderApplications();
   205→      });
   206→
   207→      loadJobs();
   208→      loadApplications();
   209→    });
   210→
   211→    async function loadJobs() {
   212→      try {
   213→        const data = await apiCall('/recruiter/jobs');
   214→        if (data.jobs) {
   215→          const select = document.getElementById('job-filter');
   216→          data.jobs.forEach(job => {
   217→            const option = document.createElement('option');
   218→            option.value = job.id;
   219→            option.textContent = job.title;
   220→            select.appendChild(option);
   221→          });
   222→        }
   223→      } catch (err) {
   224→        console.error('Failed to load jobs:', err);
   225→      }
   226→    }
   227→
   228→    async function loadApplications() {
   229→      try {
   230→        const data = await apiCall('/recruiter/applications');
   231→        if (data.applications) {
   232→          applications = data.applications;
   233→          updateStats(applications);
   234→          renderApplications();
   235→        }
   236→      } catch (err) {
   237→        console.error('Failed to load applications:', err);
   238→        document.getElementById('applications-list').innerHTML = `
   239→          <div class="empty-state">
   240→            <p>Failed to load applications</p>
   241→          </div>
   242→        `;
   243→      }
   244→    }
   245→
   246→    function updateStats(apps) {
   247→      document.getElementById('total-applications').textContent = apps.length;
   248→
   249→      const today = new Date().toDateString();
   250→      const newToday = apps.filter(a => new Date(a.applied_at).toDateString() === today).length;
   251→      document.getElementById('new-applications').textContent = newToday;
   252→
   253→      document.getElementById('reviewing-count').textContent =
   254→        apps.filter(a => a.status === 'reviewing').length;
   255→      document.getElementById('offered-count').textContent =
   256→        apps.filter(a => a.status === 'offered').length;
   257→    }
   258→
   259→    function renderApplications() {
   260→      const container = document.getElementById('applications-list');
   261→
   262→      let filtered = applications;
   263→      if (currentFilter !== 'all') {
   264→        filtered = filtered.filter(a => a.status === currentFilter);
   265→      }
   266→      if (currentJob) {
   267→        filtered = filtered.filter(a => a.job_id == currentJob);
   268→      }
   269→
   270→      if (filtered.length === 0) {
   271→        container.innerHTML = `
   272→          <div class="empty-state">
   273→            <p>No applications found</p>
   274→            <a href="/job-create.html" class="btn btn-primary btn-sm">Post a Job</a>
   275→          </div>
   276→        `;
   277→        return;
   278→      }
   279→
   280→      container.innerHTML = filtered.map(app => `
   281→        <div class="application-card">
   282→          <div class="application-header">
   283→            <div class="candidate-info">
   284→              <div class="candidate-avatar">${(app.candidate_name || 'U').charAt(0).toUpperCase()}</div>
   285→              <div class="candidate-details">
   286→                <h3>${app.candidate_name || 'Unknown'}</h3>
   287→                <p>${app.job_title || 'Position'}</p>
   288→              </div>
   289→            </div>
   290→            <div class="application-meta">
   291→              ${app.omniscore_at_apply ? `<span class="omniscore-badge">${app.omniscore_at_apply} OmniScore</span>` : ''}
   292→              <span class="status-badge ${app.status}">${app.status}</span>
   293→            </div>
   294→          </div>
   295→          <div class="application-body">
   296→            <div class="application-info">
   297→              <span class="info-item">📧 ${app.candidate_email || 'No email'}</span>
   298→              <span class="info-item">📅 Applied ${formatDate(app.applied_at)}</span>
   299→            </div>
   300→            ${app.cover_letter ? `<p class="cover-letter-preview">${app.cover_letter.substring(0, 150)}...</p>` : ''}
   301→          </div>
   302→          <div class="application-actions">
   303→            <button onclick="updateStatus(${app.id}, 'reviewing')" class="btn btn-ghost btn-sm" ${app.status !== 'applied' ? 'disabled' : ''}>
   304→              Review
   305→            </button>
   306→            <button onclick="scheduleInterview(${app.id})" class="btn btn-ghost btn-sm">
   307→              Schedule Interview
   308→            </button>
   309→            <button onclick="updateStatus(${app.id}, 'offered')" class="btn btn-primary btn-sm" ${app.status === 'offered' ? 'disabled' : ''}>
   310→              Make Offer
   311→            </button>
   312→            <button onclick="updateStatus(${app.id}, 'rejected')" class="btn btn-ghost btn-sm danger">
   313→              Reject
   314→            </button>
   315→          </div>
   316→        </div>
   317→      `).join('');
   318→    }
   319→
   320→    function formatDate(dateStr) {
   321→      const date = new Date(dateStr);
   322→      const now = new Date();
   323→      const diff = now - date;
   324→      const days = Math.floor(diff / (1000 * 60 * 60 * 24));
   325→      if (days === 0) return 'Today';
   326→      if (days === 1) return 'Yesterday';
   327→      if (days < 7) return `${days} days ago`;
   328→      return date.toLocaleDateString('en-US', { month: 'short', day: 'numeric' });
   329→    }
   330→
   331→    async function updateStatus(appId, status) {
   332→      try {
   333→        const result = await apiCall(`/recruiter/applications/${appId}/status`, {
   334→          method: 'PUT',
   335→          body: JSON.stringify({ status })
   336→        });
   337→        if (result.success) {
   338→          loadApplications();
   339→        }
   340→      } catch (err) {
   341→        alert('Failed to update status');
   342→      }
   343→    }
   344→
   345→    function scheduleInterview(appId) {
   346→      window.location.href = `/recruiter-interviews.html?schedule=${appId}`;
   347→    }
