    95→  <script>
    96→    let currentOffer = null;
    97→    let currentSession = null;
    98→
    99→    async function loadOffers() {
   100→      try {
   101→        const res = await fetch('/api/onboarding/offers/me');
   102→        const offers = await res.json();
   103→
   104→        const offersList = document.getElementById('offersList');
   105→
   106→        if (offers.length === 0) {
   107→          offersList.innerHTML = `
   108→            <div class="bg-white/10 backdrop-blur-lg rounded-xl p-8 text-center border border-white/20">
   109→              <i class="fas fa-inbox text-4xl text-gray-400 mb-4"></i>
   110→              <p class="text-gray-300">No job offers yet</p>
   111→            </div>
   112→          `;
   113→          return;
   114→        }
   115→
   116→        offersList.innerHTML = offers.map(offer => `
   117→          <div class="bg-white/10 backdrop-blur-lg rounded-xl p-6 border border-white/20">
   118→            <div class="flex justify-between items-start mb-4">
   119→              <div>
   120→                <h3 class="text-xl font-bold text-white mb-1">${offer.title}</h3>
   121→                <p class="text-gray-400">${offer.company_name}</p>
   122→              </div>
   123→              ${getOfferStatusBadge(offer.status)}
   124→            </div>
   125→
   126→            <div class="grid grid-cols-2 gap-4 mb-4">
   127→              <div>
   128→                <div class="text-gray-400 text-sm">Annual Salary</div>
   129→                <div class="text-white font-semibold text-lg">$${parseInt(offer.salary).toLocaleString()}</div>
   130→              </div>
   131→              <div>
   132→                <div class="text-gray-400 text-sm">Start Date</div>
   133→                <div class="text-white font-semibold">${offer.start_date ? new Date(offer.start_date).toLocaleDateString() : 'TBD'}</div>
   134→              </div>
   135→            </div>
   136→
   137→            <button onclick="viewOffer(${offer.id})" class="w-full bg-purple-600 hover:bg-purple-700 text-white px-6 py-3 rounded-lg font-semibold transition">
   138→              <i class="fas fa-eye mr-2"></i>
   139→              View Full Offer
   140→            </button>
   141→          </div>
   142→        `).join('');
   143→
   144→        // Check if any offers accepted - show checklists
   145→        if (offers.some(o => o.status === 'accepted')) {
   146→          loadChecklists();
   147→        }
   148→      } catch (err) {
   149→        console.error('Error loading offers:', err);
   150→      }
   151→    }
   152→
   153→    async function loadChecklists() {
   154→      try {
   155→        const res = await fetch('/api/onboarding/checklists');
   156→        const checklists = await res.json();
   157→
   158→        if (checklists.length === 0) return;
   159→
   160→        document.getElementById('checklistsSection').classList.remove('hidden');
   161→
   162→        const checklistsList = document.getElementById('checklistsList');
   163→        checklistsList.innerHTML = checklists.map(checklist => {
   164→          const items = checklist.items || [];
   165→          const completedItems = checklist.completed_items || [];
   166→          const progress = items.length > 0 ? (completedItems.length / items.length * 100) : 0;
   167→
   168→          return `
   169→            <div class="bg-white/10 backdrop-blur-lg rounded-xl p-6 border border-white/20">
   170→              <div class="flex justify-between items-start mb-4">
   171→                <div>
   172→                  <h3 class="text-xl font-bold text-white mb-1">${checklist.title}</h3>
   173→                  <p class="text-gray-400">${checklist.description || ''}</p>
   174→                </div>
   175→                <span class="text-sm text-gray-300">${completedItems.length}/${items.length} complete</span>
   176→              </div>
   177→
   178→              <div class="mb-6">
   179→                <div class="bg-gray-700 rounded-full h-3 overflow-hidden">
   180→                  <div class="bg-gradient-to-r from-purple-500 to-pink-500 h-full transition-all" style="width: ${progress}%"></div>
   181→                </div>
   182→              </div>
   183→
   184→              <div class="space-y-3">
   185→                ${items.map(item => `
   186→                  <div class="flex items-center gap-3 p-3 bg-slate-800/50 rounded-lg">
   187→                    <input
   188→                      type="checkbox"
   189→                      ${completedItems.includes(item.id) ? 'checked' : ''}
   190→                      onchange="toggleChecklistItem(${checklist.id}, ${item.id})"
   191→                      class="w-5 h-5 text-purple-600 rounded focus:ring-purple-500"
   192→                    >
   193→                    <span class="text-white ${completedItems.includes(item.id) ? 'line-through text-gray-500' : ''}">${item.task}</span>
   194→                    ${item.required ? '<span class="ml-auto text-xs text-red-400">Required</span>' : ''}
   195→                  </div>
   196→                `).join('')}
   197→              </div>
   198→            </div>
   199→          `;
   200→        }).join('');
   201→      } catch (err) {
   202→        console.error('Error loading checklists:', err);
   203→      }
   204→    }
   205→
   206→    async function viewOffer(offerId) {
   207→      try {
   208→        const res = await fetch('/api/onboarding/offers/me');
   209→        const offers = await res.json();
   210→        currentOffer = offers.find(o => o.id === offerId);
   211→
   212→        if (!currentOffer) return;
   213→
   214→        // Mark as viewed
   215→        await fetch(`/api/onboarding/offers/${offerId}/view`, { method: 'POST' });
   216→
   217→        const offerContent = document.getElementById('offerContent');
   218→        offerContent.innerHTML = `
   219→          <div class="text-center mb-6">
   220→            <h3 class="text-2xl font-bold mb-2">${currentOffer.company_name}</h3>
   221→            <h4 class="text-xl text-gray-600">Offer of Employment</h4>
   222→          </div>
   223→
   224→          <div class="space-y-4">
   225→            <p>Dear ${currentOffer.candidate_name || 'Candidate'},</p>
   226→
   227→            <p>We are pleased to offer you the position of <strong>${currentOffer.title}</strong> at ${currentOffer.company_name}.</p>
   228→
   229→            <div class="bg-gray-50 p-4 rounded-lg">
   230→              <h5 class="font-bold mb-2">Compensation & Benefits</h5>
   231→              <ul class="space-y-2">
   232→                <li><strong>Annual Salary:</strong> $${parseInt(currentOffer.salary).toLocaleString()}</li>
   233→                <li><strong>Start Date:</strong> ${currentOffer.start_date ? new Date(currentOffer.start_date).toLocaleDateString() : 'To be determined'}</li>
   234→                ${currentOffer.benefits ? `<li><strong>Benefits:</strong> ${currentOffer.benefits}</li>` : ''}
   235→              </ul>
   236→            </div>
   237→
   238→            <p>We look forward to welcoming you to our team!</p>
   239→
   240→            <p class="text-sm text-gray-600 mt-6">
   241→              This offer is contingent upon successful completion of background checks and verification of eligibility to work.
   242→            </p>
   243→          </div>
   244→        `;
   245→
   246→        const offerActions = document.getElementById('offerActions');
   247→        if (currentOffer.status === 'sent') {
   248→          offerActions.innerHTML = `
   249→            <button onclick="acceptOffer()" class="flex-1 bg-green-600 hover:bg-green-700 text-white px-6 py-3 rounded-lg font-semibold transition">
   250→              <i class="fas fa-check mr-2"></i>
   251→              Accept Offer
   252→            </button>
   253→            <button onclick="showDeclineReason()" class="flex-1 bg-red-600 hover:bg-red-700 text-white px-6 py-3 rounded-lg font-semibold transition">
   254→              <i class="fas fa-times mr-2"></i>
   255→              Decline Offer
   256→            </button>
   257→          `;
   258→        } else if (currentOffer.status === 'accepted') {
   259→          offerActions.innerHTML = `
   260→            <div class="flex-1 text-center text-green-400">
   261→              <i class="fas fa-check-circle mr-2"></i>
   262→              You accepted this offer on ${new Date(currentOffer.accepted_at).toLocaleDateString()}
   263→            </div>
   264→          `;
   265→        } else if (currentOffer.status === 'declined') {
   266→          offerActions.innerHTML = `
   267→            <div class="flex-1 text-center text-red-400">
   268→              <i class="fas fa-times-circle mr-2"></i>
   269→              You declined this offer on ${new Date(currentOffer.declined_at).toLocaleDateString()}
   270→            </div>
   271→          `;
   272→        }
   273→
   274→        document.getElementById('offerModal').classList.remove('hidden');
   275→        document.getElementById('offerModal').classList.add('flex');
   276→      } catch (err) {
   277→        console.error('Error viewing offer:', err);
   278→      }
   279→    }
