   281→    async function acceptOffer() {
   282→      if (!confirm('Accept this job offer?')) return;
   283→
   284→      try {
   285→        const res = await fetch(`/api/onboarding/offers/${currentOffer.id}/accept`, {
   286→          method: 'POST',
   287→          headers: { 'Content-Type': 'application/json' },
   288→          body: JSON.stringify({ signature_url: 'digital_signature_placeholder' })
   289→        });
   290→
   291→        if (!res.ok) throw new Error('Failed to accept offer');
   292→
   293→        alert('Congratulations! Offer accepted successfully.');
   294→        closeOfferModal();
   295→        loadOffers();
   296→      } catch (err) {
   297→        console.error('Error accepting offer:', err);
   298→        alert('Failed to accept offer. Please try again.');
   299→      }
   300→    }
   301→
   302→    function showDeclineReason() {
   303→      const reason = prompt('Please tell us why you are declining this offer (optional):');
   304→      if (reason !== null) {
   305→        declineOffer(reason);
   306→      }
   307→    }
   308→
   309→    async function declineOffer(reason) {
